interface Todo {
  id: number;
  task: string;
  completed: boolean;
}

let todos: Todo[] = [];

function addTodo(task: string): void {
  const newTodo: Todo = {
    id: Date.now(),
    task,
    completed: false
  };
  todos.push(newTodo);
  renderTodos();
}

function renderTodos(): void {
  const list = document.getElementById('todo-list');
  if (!list) return;

  list.innerHTML = '';

  todos.forEach(todo => {
    const item = document.createElement('li');
    item.textContent = todo.task;
    if (todo.completed) {
      item.style.textDecoration = 'line-through';
    }

    // Add a button to toggle completion
    const toggleBtn = document.createElement('button');
    toggleBtn.textContent = todo.completed ? 'Undo' : 'Complete';
    toggleBtn.onclick = () => toggleComplete(todo.id);

    // Add a button to remove the todo
    const deleteBtn = document.createElement('button');
    deleteBtn.textContent = 'Delete';
    deleteBtn.onclick = () => deleteTodo(todo.id);

    item.appendChild(toggleBtn);
    item.appendChild(deleteBtn);

    list.appendChild(item);
  });
}

function toggleComplete(id: number): void {
  todos = todos.map(todo => 
    todo.id === id ? { ...todo, completed: !todo.completed } : todo
  );
  renderTodos();
}

function deleteTodo(id: number): void {
  todos = todos.filter(todo => todo.id !== id);
  renderTodos();
}

type Shape =
  | { kind: 'circle'; radius: number }
  | { kind: 'square'; sideLength: number };

function getArea(shape: Shape): number {
  switch (shape.kind) {
    case 'circle':
      return Math.PI * shape.radius ** 2;
    case 'square':
      return shape.sideLength ** 2;
    default:
      // Using exhaustiveness check to catch unhandled cases
      const _exhaustiveCheck: never = shape;
      return _exhaustiveCheck;
  }
}

